  ('pukao-39f5e973-moex-00244', 'pukao-39f5e973', 'pukao-39f5e973-moex-110-156cbda0', 'sub-pukao-39f5e973-02', NULL, 'single_choice', '關於程序排程（ProcessScheduling）演算法，下列敘述何者正確？', '["輪流（RoundRobin,RR）演算法有護衛效應（ConvoyEffect）", "先到先服務（First-Come,First-Served,FCFS）演算法會有飢餓現象（Starvation）", "多層次回授佇列（MultilevelFeedbackQueue）排程可以用來實現最短工作優先的目的", "不可搶奪式最短工作優先（Non-preemptiveShortestJobFirst）演算法可以得到最小平均等待時間"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:52+00:00", "source_pdf_sha1": "14b29f1b1063", "answer_pdf_sha1": "2de69e704cf1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "451", "s": "1217", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "計算機概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "資訊處理"}'::jsonb, NULL),
